// src/components/FormAgendamento.jsx
import React, { useEffect, useState, useRef } from "react";
import axios from "axios";
import { useAuth } from "../context/AuthContext";

export default function FormAgendamento({
  onNovoAgendamento,
  agendamentoEditando,
  onFimEdicao,
}) {
  const { user } = useAuth();
  const token = user?.token;
  const role = user?.role; // 'recepcao' ou 'aluno'

  // estado do form…
  const [tipoAtendimento, setTipoAtendimento] = useState("Novo");
  const [pacientes, setPacientes] = useState([]);
  const [buscaPaciente, setBuscaPaciente] = useState("");
  const [pacienteId, setPacienteId] = useState("");
  const [nomePaciente, setNomePaciente] = useState("");
  const [telefone, setTelefone] = useState("");
  const [showLista, setShowLista] = useState(false);

  const [disciplinas, setDisciplinas] = useState([]);
  const [alunos, setAlunos] = useState([]);

  const [disciplinaId, setDisciplinaId] = useState("");
  const [data, setData] = useState("");
  const [hora, setHora] = useState("");
  const [observacoes, setObservacoes] = useState("");

  const [operadorId, setOperadorId] = useState("");
  const [auxiliar1Id, setAuxiliar1Id] = useState("");

  const [mensagem, setMensagem] = useState("");
  const inputRef = useRef(null);

  // busca iniciais
  useEffect(() => {
    if (!token) return;

    const config = { headers: { Authorization: `Bearer ${token}` } };

    axios.get("/api/disciplinas", config).then(r => setDisciplinas(r.data));
    axios.get("/api/pacientes", config).then(r => setPacientes(r.data));

    const urlAlunos = role === "recepcao" ? "/api/alunos" : "/api/alunos/me";
    axios
      .get(urlAlunos, config)
      .then((r) => {
        const list = Array.isArray(r.data) ? r.data : [r.data];
        setAlunos(list);
      })
      .catch(() =>
        setMensagem("Não foi possível carregar lista de alunos.")
      );
  }, [token, role]);

  // fecha dropdown
  useEffect(() => {
    const f = (e) => {
      if (inputRef.current && !inputRef.current.contains(e.target)) {
        setShowLista(false);
      }
    };
    document.addEventListener("mousedown", f);
    return () => document.removeEventListener("mousedown", f);
  }, []);

  // se editar…
  useEffect(() => {
    if (agendamentoEditando) {
      setTipoAtendimento(
        agendamentoEditando.status === "Solicitado"
          ? "Solicitar"
          : agendamentoEditando.status
      );
      setDisciplinaId(String(agendamentoEditando.disciplina_id || ""));
      setPacienteId(agendamentoEditando.paciente_id || "");
      setNomePaciente(agendamentoEditando.nome_paciente || "");
      setTelefone(agendamentoEditando.telefone || "");
      setData(agendamentoEditando.data?.slice(0, 10) || "");
      setHora(agendamentoEditando.hora || "19:00");
      setObservacoes(agendamentoEditando.observacoes || "");
      setOperadorId(
        String(agendamentoEditando.aluno_id || agendamentoEditando.operador_id || "")
      );
      setAuxiliar1Id(String(agendamentoEditando.auxiliar1_id || ""));
      setBuscaPaciente(
        (agendamentoEditando.nome_paciente || "") +
          (agendamentoEditando.telefone
            ? " - " + agendamentoEditando.telefone
            : "")
      );
      setShowLista(false);
    } else {
      // limpa tudo
      setTipoAtendimento("Novo");
      setDisciplinaId("");
      setPacienteId("");
      setNomePaciente("");
      setTelefone("");
      setData("");
      setHora("19:00");
      setObservacoes("");
      setOperadorId("");
      setAuxiliar1Id("");
      setBuscaPaciente("");
      setShowLista(false);
    }
  }, [agendamentoEditando]);

  const pacientesFiltrados = pacientes.filter((p) => {
    const t = buscaPaciente.toLowerCase();
    return (
      p.nome.toLowerCase().includes(t) ||
      p.telefone?.includes(t)
    );
  });

  const selecionarPaciente = (p) => {
    setPacienteId(p.id);
    setNomePaciente(p.nome);
    setTelefone(p.telefone);
    setBuscaPaciente(
      p.nome + (p.telefone ? " - " + p.telefone : "")
    );
    setShowLista(false);
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    setMensagem("");

    if (!disciplinaId) {
      setMensagem("Selecione uma disciplina.");
      return;
    }
    if (!operadorId) {
      setMensagem("Selecione um operador.");
      return;
    }
    if (!pacienteId && tipoAtendimento !== "Solicitar") {
      setMensagem("Selecione um paciente.");
      return;
    }
    if (operadorId === auxiliar1Id) {
      setMensagem("Operador e auxiliar devem ser diferentes.");
      return;
    }

    const payload = {
      disciplina_id: disciplinaId,
      paciente_id:
        tipoAtendimento === "Solicitar" ? null : pacienteId,
      nome_paciente:
        tipoAtendimento === "Solicitar" ? null : nomePaciente,
      telefone:
        tipoAtendimento === "Solicitar" ? null : telefone,
      data,
      hora,
      observacoes:
        tipoAtendimento === "Solicitar" ? null : observacoes,
      aluno_id: operadorId,
      auxiliar1_id: auxiliar1Id || null,
      status:
        tipoAtendimento === "Solicitar"
          ? "Solicitado"
          : tipoAtendimento,
      solicitado_por_recepcao:
        tipoAtendimento === "Solicitar",
    };

    const config = {
      headers: { Authorization: `Bearer ${token}` },
    };

    const req = agendamentoEditando
      ? axios.put(
          `/api/agendamentos/${agendamentoEditando.id}`,
          payload,
          config
        )
      : axios.post("/api/agendamentos", payload, config);

    req
      .then(() => {
        setMensagem(
          agendamentoEditando
            ? "Agendamento atualizado!"
            : "Agendamento cadastrado!"
        );
        onNovoAgendamento?.();
        if (agendamentoEditando) onFimEdicao?.();
        else {
          // limpa
          setDisciplinaId("");
          setPacienteId("");
          setNomePaciente("");
          setTelefone("");
          setData("");
          setHora("19:00");
          setObservacoes("");
          setOperadorId("");
          setAuxiliar1Id("");
          setBuscaPaciente("");
        }
      })
      .catch((err) => {
        console.error(err.response?.data || err.message);
        setMensagem(
          agendamentoEditando
            ? "Erro ao atualizar."
            : "Erro ao cadastrar."
        );
      });
  };

  return (
    <div className="bg-white mx-auto max-w-2xl rounded-2xl p-6">
      <form onSubmit={handleSubmit} autoComplete="off">
        <h2 className="text-2xl font-bold mb-6 text-gray-800">
          Agendar Paciente
        </h2>

        {/* Tipo */}
        <div className="flex flex-wrap gap-2 mb-6">
          {["Novo", "Retorno", "Solicitar"].map((t) => (
            <button
              key={t}
              type="button"
              onClick={() => setTipoAtendimento(t)}
              className={`px-4 py-1 rounded-full font-semibold transition ${
                tipoAtendimento === t
                  ? "bg-[#D9E0FF] text-gray-800"
                  : "bg-gray-200 text-gray-800 hover:bg-gray-300"
              }`}
            >
              {t === "Solicitar"
                ? "Solicitar para Recepção"
                : t}
            </button>
          ))}
        </div>

        {/* Disciplina */}
        <div className="mb-6">
          <label className="block mb-1 font-medium">
            Disciplina
          </label>
          <div className="flex flex-wrap gap-2">
            {disciplinas.map((d) => (
              <button
                key={d.id}
                type="button"
                className={`px-4 py-1 rounded-full border transition ${
                  disciplinaId === String(d.id)
                    ? "bg-[#D9E0FF] text-gray-800 font-semibold"
                    : "bg-gray-100 text-gray-800 hover:bg-gray-300"
                }`}
                onClick={() =>
                  setDisciplinaId(String(d.id))
                }
              >
                {d.nome}
              </button>
            ))}
          </div>
          {disciplinaId === "" && (
            <span className="text-red-600 text-xs mt-2 block">
              Selecione uma disciplina
            </span>
          )}
        </div>

        {/* Paciente */}
        {tipoAtendimento !== "Solicitar" && (
          <div
            className="mb-6 relative"
            ref={inputRef}
          >
            <label className="block mb-1 font-medium">
              Paciente
            </label>
            <input
              className="w-full border rounded px-3 py-2"
              placeholder="Digite nome ou telefone"
              value={buscaPaciente}
              onChange={(e) => {
                setBuscaPaciente(e.target.value);
                setShowLista(true);
                setPacienteId("");
              }}
              onFocus={() => setShowLista(true)}
              required
            />
            {showLista && buscaPaciente && (
              <ul className="absolute z-10 bg-white border w-full rounded shadow max-h-40 overflow-auto">
                {pacientesFiltrados.length ? (
                  pacientesFiltrados.map((p) => (
                    <li
                      key={p.id}
                      className="px-3 py-2 cursor-pointer hover:bg-blue-100"
                      onClick={() =>
                        selecionarPaciente(p)
                      }
                    >
                      {p.nome} - {p.telefone}
                    </li>
                  ))
                ) : (
                  <li className="px-3 py-2 text-gray-400">
                    Nenhum paciente encontrado
                  </li>
                )}
              </ul>
            )}
            {pacienteId && (
              <div className="mt-2 space-y-2">
                <input
                  className="w-full border rounded px-3 py-2 bg-gray-100"
                  value={nomePaciente}
                  readOnly
                />
                <input
                  className="w-full border rounded px-3 py-2 bg-gray-100"
                  value={telefone}
                  readOnly
                />
              </div>
            )}
          </div>
        )}

        {/* Data e Hora */}
        <div className="mb-6 flex flex-col md:flex-row gap-4">
          <div className="flex-1">
            <label className="block mb-1 font-medium">
              Data do Atendimento
            </label>
            <input
              type="date"
              className="w-full border rounded-full px-3 py-2"
              value={data}
              onChange={(e) => setData(e.target.value)}
              required
            />
          </div>
          <div className="flex-1">
            <label className="block mb-1 font-medium">
              Hora do Atendimento
            </label>
            <input
              type="time"
              className="w-full border rounded-full px-3 py-2"
              value={hora}
              onChange={(e) => setHora(e.target.value)}
              required
            />
          </div>
        </div>

        {/* Operador / Auxiliar */}
        <div className="mb-6">
          <label className="block mb-4 font-medium">
            Alunos que irão realizar o atendimento
          </label>
          <div className="flex flex-col md:flex-row gap-4">
            <div className="flex-1">
              <label className="block mb-1 text-sm font-semibold">
                Operador
              </label>
              <select
                required
                className="w-full border rounded px-3 py-2"
                value={operadorId}
                onChange={(e) =>
                  setOperadorId(e.target.value)
                }
              >
                <option value="">
                  Selecione o operador
                </option>
                {alunos.map((a) => (
                  <option key={a.id} value={a.id}>
                    {a.nome}
                  </option>
                ))}
              </select>
            </div>
            <div className="flex-1">
              <label className="block mb-1 text-sm font-semibold">
                Auxiliar
              </label>
              <select
                className="w-full border rounded px-3 py-2"
                value={auxiliar1Id}
                onChange={(e) =>
                  setAuxiliar1Id(e.target.value)
                }
              >
                <option value="">
                  Selecione o auxiliar
                </option>
                {alunos.map((a) => (
                  <option key={a.id} value={a.id}>
                    {a.nome}
                  </option>
                ))}
              </select>
            </div>
          </div>
        </div>

        {/* Botões */}
        <div className="mt-8 flex flex-col md:flex-row gap-4">
          <button
            type="submit"
            className="bg-[#3172C0] hover:bg-[#083A76] text-white font-bold py-2 px-6 rounded-full"
          >
            {tipoAtendimento === "Solicitar"
              ? "Solicitar para Recepção"
              : "Agendar Paciente"}
          </button>
          {agendamentoEditando && (
            <button
              type="button"
              className="bg-[#DA3648] text-white hover:bg-[#BC3140] px-4 py-2 rounded-full"
              onClick={onFimEdicao}
            >
              Cancelar
            </button>
          )}
        </div>

        {mensagem && (
          <p className="mt-4 text-red-600">{mensagem}</p>
        )}
      </form>
    </div>
  );
}
